    long long cur_min = 0;
    int key = 0;
    for(int i = 1; i <= 2*k; i++){
        int idx = max(0, i-k);
        if(key < idx){
            cur_min = INT_MAX;
            key++;
            for(int j = idx; j < i; j++){
