class Solution {
public:
    vector<double> calcEquation(vector<vector<string>>& equations, vector<double>& values, vector<vector<string>>& queries) {
        unordered_map<string, vector<pair<string, double>>> map;
        //建图
        for(int i = 0; i < values.size(); i ++){
            string a = equations[i][0];
            string b = equations[i][1];
            double cost = values[i];
            map[a].push_back({b, cost});
            map[b].push_back({a, 1/cost});
        }

        auto dfs = [&](this auto& dfs, string cur, string des, double cos, unordered_set<string> isok)->double{
            if(cur == des){
                return cos;
            }
            for(auto [x, y] : map[cur]){
                if(isok.contains(x)) continue;
                else{
                    isok.insert(x);
                    cos *= y;
                    cos = dfs(x, des, cos, isok);
                }
            }
            return -1;
        };
        vector<double> ans_set;
        for(auto& str : queries){
            string x = str[0];
            string y = str[1];
            unordered_set<string> isok;
            double ans = dfs(x, y, 1.0, isok);
            ans_set.push_back(ans);
        }
        return ans_set;
    }
};
