class Solution {
public:
    string simplifyPath(string path) {
        vector<string> stack;
        for(auto&& str : path | views::split('/')){
            string s(str.begin(), str.end());
            if(s == "." || s.empty()) continue;
            else if(s != "..") stack.push_back(s);
            else{
                if(!stack.empty()){
                    stack.pop_back();
                }
            }
        }
        string ans;
        for(string& s : stack){
            ans += '/';
            ans += s;
        }

        return ans.empty() ? "/" : ans;
    }
};
