/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {
        int n = inorder.size();
        unordered_map<int, int> map;
        for(int i = 0; i < inorder.size(); i++){
            map[inorder[i]] = i;
        }
        auto dfs = [&](auto&& dfs, vector<int>& preorder, vector<int>& inorder, int prel, int prer, int inol, int inor)->TreeNode* {
            if(prel > prer){
                return nullptr;
            }
            int value = preorder[prel];
            int k = map[value];
            TreeNode* root = new TreeNode(value);

            int left_size = k - inol;

            //left_tree
            root->left = dfs(dfs, preorder, inorder, prel + 1, prel + left_size, inol, k - 1);

            //right_tree;
            root->right = dfs(dfs, preorder, inorder, prel + left_size + 1, prer, k + 1, inor);

            return root;
        };

        return dfs(dfs, preorder, inorder, 0, n-1, 0, n-1);
    }
};
