class Solution {
public:
    vector<int> maxSlidingWindow(vector<int>& nums, int k) {
        deque<int> dq;       // 存放下标，对应元素单调递减
        vector<int> ans;

        for (int i = 0; i < nums.size(); i++) {

            // 1. 删除已经滑出窗口的元素
            if (!dq.empty() && dq.front() <= i - k) {
                dq.pop_front();
            }

            // 2. 删除队尾所有比当前元素小的元素
            // 它们以后不可能成为窗口最大值
            while (!dq.empty() && nums[dq.back()] <= nums[i]) {
                dq.pop_back();
            }

            // 3. 当前元素下标入队
            dq.push_back(i);

            // 4. 窗口形成后，记录最大值
            if (i >= k - 1) {
                ans.push_back(nums[dq.front()]);
            }
        }

        return ans;
    }
};
