class Solution {
public:
    int subarraySum(vector<int>& nums, int k) {
        int n = nums.size();
        vector<long long> sum(n+1);
        sum[0] = 0;
        sum[1] = nums[0];
        for(int i = 2; i < n+1; i++){
            sum[i] = sum[i-1] + nums[i-1];
        }
        int left = 0, right = 1, ans = 0;
        while(right <= n){
            if(left == right){
                right++;
                continue;
            }
            if(sum[right] - sum[left] == k) ans++;
            else if(sum[right] - sum[left] < k){
                right++;
                continue;
            }
            else{
                left++;
                continue;
            }
            right++;
        }
        return ans;
    }
};
