class Solution {
public:
    int subarraySum(vector<int>& nums, int k) {
        unordered_map<long long, int> cnt;

        // 数组开始前的前缀和为 0
        cnt[0] = 1;

        long long prefix = 0;
        int ans = 0;

        for (int x : nums) {
            prefix += x;

            // B = A - k
            ans += cnt[prefix - k];

            // 保存当前前缀和 A
            cnt[prefix]++;
        }

        return ans;
    }
};
