class Solution {
public:
    int longestConsecutive(vector<int>& nums) {
        unordered_set<int> st(nums.begin(), nums.end());

        int ans = 0;

        for (int x : st) {
            // 如果 x - 1 存在，说明 x 不是连续序列的起点
            if (x != INT_MIN && st.count(x - 1)) {
                continue;
            }

            // x 是某个连续序列的起点
            int current = x;
            int length = 1;

            // 不断寻找 current + 1
            while (current != INT_MAX && st.count(current + 1)) {
                current++;
                length++;
            }

            ans = max(ans, length);
        }

        return ans;
    }
};
```

